const result = [];
let morning_index = 0;
let evening_index = 0;

const MORNING_HOUR = 9;
const EVENING_HOUR = 19;
const WINDOW_MINUTES = 90;

for (const item of $input.all()) {
  const s = item.json;

  const product_meta = typeof s.product_meta === 'string'
    ? JSON.parse(s.product_meta)
    : (s.product_meta ?? {});

  const timezone = s.timezone || 'Asia/Seoul';

  const local_time_str = new Date().toLocaleString('en-US', {
    timeZone: timezone,
    hour: 'numeric',
    minute: 'numeric',
    hour12: false,
  });
  const [local_h, local_m] = local_time_str.split(':').map(Number);
  const local_minutes = local_h * 60 + local_m;

  const morning_target = MORNING_HOUR * 60;
  const evening_target = EVENING_HOUR * 60;

  const diff_morning = Math.abs(local_minutes - morning_target);
  const diff_evening = Math.abs(local_minutes - evening_target);
  const dist_morning = Math.min(diff_morning, 24 * 60 - diff_morning);
  const dist_evening = Math.min(diff_evening, 24 * 60 - diff_evening);

  let slot_type = null;
  let slot_hour = null;

  if (dist_morning <= WINDOW_MINUTES) {
    slot_type = 'morning';
    slot_hour = MORNING_HOUR;
  } else if (dist_evening <= WINDOW_MINUTES) {
    slot_type = 'evening';
    slot_hour = EVENING_HOUR;
  } else {
    continue;
  }

  const today_local = new Date().toLocaleDateString('en-CA', { timeZone: timezone });
  const target_local_iso = `${today_local}T${String(slot_hour).padStart(2, '0')}:00:00`;
  const ref_local = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));
  const tz_offset_ms = new Date().getTime() - ref_local.getTime();
  const base_utc_ms = new Date(target_local_iso + 'Z').getTime() + tz_offset_ms;
  const stagger_index = slot_type === 'morning' ? morning_index++ : evening_index++;
  const stagger_ms = stagger_index * 5 * 60 * 1000;
  const scheduled_at = new Date(base_utc_ms + stagger_ms).toISOString();

  result.push({
    json: {
      slot_type,
      slot_hour,
      auth_user_id: s.auth_user_id,
      session_id: s.session_id,
      product_session_id: s.product_session_id,
      discord_id: s.discord_id,
      display_name: s.display_name || '학습자',
      timezone,
      session_number: s.session_number ?? 1,
      session_label: `Session ${s.session_number ?? ''}`.trim(),
      product_id: s.product_id,
      product_name: s.product_name ?? '',
      product_slug: s.product_slug ?? '',
      is_story: !!(product_meta?.story),
      today_local,
      scheduled_at,
    }
  });
}

return result;

const user = $input.first().json;

const slot_hour          = user.slot_hour;
const auth_user_id       = user.auth_user_id;
const session_id         = user.session_id;
const product_session_id = user.product_session_id;
const product_id         = user.product_id;
const today_local        = user.today_local;
const today_utc_start    = new Date(`${today_local}T00:00:00.000Z`).toISOString();
const hour_tag           = `cheer:${String(slot_hour).padStart(2, '0')}`;
const product_name       = user.product_name ?? '';
const session_label      = `Session ${user.session_number ?? ''}`;
const safe_product_name  = product_name.replace(/'/g, "''");

// SQL: dedup check
const dedup_sql = `SELECT schedule_id FROM nv2_schedules
WHERE auth_user_id = '${auth_user_id}'
  AND schedule_type = 'cheer'
  AND message_body LIKE '${hour_tag}|${safe_product_name}|%'
  AND created_at >= '${today_utc_start}'
LIMIT 1`;

// SQL: today session status + next session id
const session_status_sql = `
SELECT
  s.status AS today_status,
  next_ps.id AS next_product_session_id,
  next_ps.session_number AS next_session_number
FROM nv2_sessions s
LEFT JOIN nv2_product_sessions cur_ps ON cur_ps.id = s.product_session_id
LEFT JOIN nv2_product_sessions next_ps
  ON next_ps.product_id = cur_ps.product_id
  AND next_ps.session_number = cur_ps.session_number + 1
  AND next_ps.is_active = true
WHERE s.session_id = '${session_id}'
LIMIT 1`;

// SQL: pick ONE random stage, then fetch all its cards (title+description+example)
// This ensures title card is always included
const card_sql_for = (ps_id) => user.is_story
  ? `SELECT c.card_type, c.card_data
     FROM nv2_product_session_stages pss
     JOIN nv2_stages st ON st.id = pss.stage_id
     JOIN nv2_cards  c  ON c.stage_id = st.id
     WHERE pss.product_session_id = '${ps_id}'
       AND st.stage_type = 'story'
       AND c.card_type = 'story'
     LIMIT 1`
  : `SELECT st.id AS stage_id, c.card_type, c.card_data
     FROM nv2_product_session_stages pss
     JOIN nv2_stages st ON st.id = pss.stage_id
     JOIN nv2_cards  c  ON c.stage_id = st.id
     WHERE pss.product_session_id = '${ps_id}'
       AND st.stage_type = 'learning'
       AND c.card_type IN ('title', 'description', 'example')
       AND st.id = (
         SELECT st2.id
         FROM nv2_product_session_stages pss2
         JOIN nv2_stages st2 ON st2.id = pss2.stage_id
         WHERE pss2.product_session_id = '${ps_id}'
           AND st2.stage_type = 'learning'
         ORDER BY RANDOM()
         LIMIT 1
       )`;

const today_card_sql = card_sql_for(product_session_id);

return [{
  json: {
    ...user,
    hour_tag,
    product_name,
    session_label,
    dedup_sql,
    session_status_sql,
    today_card_sql,
  }
}];

const dedup_rows = $input.all();
if (dedup_rows.length > 0 && dedup_rows[0].json.schedule_id) {
  return [{ json: { _skip: true } }];
}
const user = $('Prepare Queries').first().json;
return [{ json: { ...user, _skip: false } }];

const user = $('Check Dedup Result').first().json;
const all_rows = $('Merge').all();

// Session status row
const status_row = all_rows.find(r => r.json.today_status !== undefined);
const today_status           = status_row?.json?.today_status ?? 'pending';
const next_product_session_id = status_row?.json?.next_product_session_id ?? null;
const next_session_number     = status_row?.json?.next_session_number ?? null;

const is_completed = today_status === 'completed';
const use_next     = is_completed && !!next_product_session_id;

// Content rows (cards)
const content_rows = all_rows.filter(r => r.json.card_type !== undefined);

let card_word = '';
let card_meaning = '';
let card_example = '';
let card_example_translation = '';
let script_tip = ''; // memory tip from details.explanation (for hiragana/katakana)

if (user.is_story) {
  const row = content_rows?.[0]?.json;
  const cd = typeof row?.card_data === 'string'
    ? JSON.parse(row.card_data)
    : (row?.card_data ?? {});
  card_word = cd.hook_text ?? '';
} else {
  // Group by stage_id
  const by_stage = {};
  for (const row of content_rows) {
    const r = row.json;
    if (!by_stage[r.stage_id]) by_stage[r.stage_id] = {};
    const cd = typeof r.card_data === 'string'
      ? JSON.parse(r.card_data)
      : (r.card_data ?? {});
    by_stage[r.stage_id][r.card_type] = cd;
  }

  for (const [, cards] of Object.entries(by_stage)) {
    const title_front = cards['title']?.presentation?.front ?? cards['title']?.text ?? '';
    const title_back  = cards['title']?.presentation?.back  ?? '';
    const desc_back   = cards['description']?.presentation?.back ?? cards['description']?.text ?? '';
    const desc_expl   = cards['description']?.details?.explanation ?? '';
    const ex_front    = cards['example']?.presentation?.front ?? cards['example']?.text ?? '';
    const ex_back     = cards['example']?.presentation?.back  ?? cards['example']?.back  ?? '';
    const ex_expl     = cards['example']?.details?.explanation ?? '';

    // Require at least a word to proceed
    const word = title_front || desc_back || '';
    if (!word) continue;

    card_word    = title_front;
    card_meaning = title_back || desc_back;
    card_example = ex_front;
    card_example_translation = ex_back;

    // script_tip: best explanation text for hiragana/katakana memory
    // Prefer example explanation (e.g. 'すし = 초밥'), then description explanation
    script_tip = ex_expl || desc_expl || '';
    break;
  }
}

const target_session_label = use_next
  ? `Session ${next_session_number}`
  : user.session_label;

return [{
  json: {
    ...user,
    today_status,
    is_completed,
    use_next,
    next_product_session_id,
    next_session_number,
    target_session_label,
    card_word,
    card_meaning,
    card_example,
    card_example_translation,
    script_tip,
  }
}];

const d = $input.first().json;

// Content type detection
const is_script = !!(d.product_slug?.includes('hiragana') || d.product_slug?.includes('katakana'));
const is_story  = d.is_story;

// Build card info block
let card_info = '(콘텐츠 준비 중)';
if (d.card_word) {
  const lines = [
    `단어/표현: ${d.card_word}${d.card_meaning ? ` (${d.card_meaning})` : ''}`,
  ];
  if (is_script && d.script_tip) {
    lines.push(`기억 팁: ${d.script_tip}`);
  }
  if (!is_script && d.card_example) {
    lines.push(`예문: ${d.card_example}`);
    if (d.card_example_translation) lines.push(`예문 번역: ${d.card_example_translation}`);
  }
  card_info = lines.join('\n');
}

const system_prompt = `You are Leni, a 15-year-old German girl who studies languages alongside the user.
Tone: warm, bright, slightly playful. Korean 해요체 (존댓말). Plain text only, no markdown.
You must respond in JSON format.
Respond ONLY with a JSON object with two keys: incomplete_message, complete_message.
No preamble, no explanation, no code fences. Just the raw JSON.`;

const context_line = `학습 상품: ${d.product_name} / 세션: ${d.target_session_label}`;

let incomplete_instruction = '';
let complete_instruction   = '';

if (is_script) {
  incomplete_instruction =
    '- 2~3줄 이내\n' +
    '- 글자 모양이나 발음을 기억하는 재미있는 팁 1줄 포함 (기억 팁 활용)\n' +
    '- 마지막 줄에 학습 링크 클릭 유도 1줄\n' +
    '- 이모지 1개';
  complete_instruction =
    '- 2~3줄 이내\n' +
    '- 칭찬 1줄\n' +
    '- 배운 글자가 포함된 간단한 단어나 소리 조합 예시 1줄\n' +
    '- 이모지 1개';
} else if (is_story) {
  incomplete_instruction =
    '- 2~3줄 이내\n' +
    '- 이야기 내용으로 궁금증을 유발하는 훅 1줄\n' +
    '- 마지막 줄에 학습 링크 클릭 유도 1줄\n' +
    '- 이모지 1개';
  complete_instruction =
    '- 2~3줄 이내\n' +
    '- 칭찬 1줄\n' +
    '- 오늘 배운 단어 활용 팁 1줄\n' +
    '- 이모지 1개';
} else {
  incomplete_instruction =
    '- 2~3줄 이내\n' +
    '- 카드의 단어/표현을 실생활에서 쓸 수 있는 활용 예 1문장 포함\n' +
    '- 마지막 줄에 학습 링크 클릭 유도 1줄\n' +
    '- 이모지 1개';
  complete_instruction =
    '- 2~3줄 이내\n' +
    '- 칭찬 1줄\n' +
    '- 카드의 단어/표현 또 다른 활용 예 1문장\n' +
    '- 이모지 1개';
}

const user_prompt =
  `사용자: ${d.display_name}\n` +
  `${context_line}\n` +
  `\n카드 정보:\n${card_info}\n` +
  `\n---\n` +
  `\nincomplete_message (세션 미완료 사용자용):\n${incomplete_instruction}\n` +
  `\ncomplete_message (세션 완료 사용자용):\n${complete_instruction}`;

return [{
  json: {
    ...d,
    system_prompt,
    user_prompt,
  }
}];

const openai_res = $input.first().json;
const user = $('Build OpenAI Prompt').first().json;

let incomplete_message = '';
let complete_message   = '';
try {
  const content = openai_res.output ?? '{}';
  const parsed  = typeof content === 'string' ? JSON.parse(content) : content;
  incomplete_message = (parsed.incomplete_message ?? '').trim();
  complete_message   = (parsed.complete_message   ?? '').trim();
} catch (e) {
  return [];
}

if (!incomplete_message || !complete_message) return [];

// message_body: cheer:HH|product_name|session_label|incomplete_message|||complete_message
const message_body = [
  `${user.hour_tag}|${user.product_name}|${user.session_label}|${incomplete_message}`,
  complete_message,
].join('|||');

const nudge_origin = 'https://nudge.neowithai.com';
const delivery_url = `${nudge_origin}/sessions/${user.session_id}`;

return [{
  json: {
    auth_user_id:  user.auth_user_id,
    schedule_type: 'cheer',
    delivery_url,
    message_body,
    scheduled_at:  user.scheduled_at,
  }
}];
